// Package perf provides a reusable GraphQL performance harness for the DDx
// server. It seeds realistic on-disk fixtures (projects × beads, docgraph,
// agent sessions) using the real storage primitives, then drives each GraphQL
// query shape through both the in-process StateProvider and the full HTTP
// handler while recording p50/p95/p99 latencies.
//
// The harness exists so performance work can be grounded in numbers rather
// than anecdote (ddx-9ce6842a Part 1). New query shapes are added by
// appending to the target table in harness.go — the fixture and measurement
// layers stay unchanged.
package perf

import (
	"fmt"
	"net/http"
	"os"
	"path/filepath"
	"runtime"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/server"
)

// BeadFixtureSpec describes the shape of a generated workspace.
//
// The defaults (10 projects × 500 beads = 5,000 beads) match the ddx-9ce6842a
// acceptance criteria §5, and the per-query floor of ≥1,000 records documented
// in the 2026-04-22 user directive on fixture size. Consumers that want a
// heavier run should raise BeadsPerProject rather than Projects so the
// distribution stays comparable.
type BeadFixtureSpec struct {
	// Projects is the number of registered projects. Must be ≥ 1.
	Projects int
	// BeadsPerProject is the number of beads seeded in each project.
	// Combined with Projects this yields the total bead corpus size.
	BeadsPerProject int
	// ClosedRatio (0..1) controls the fraction of seeded beads written with
	// status=closed. Defaults to 0.3. A realistic mix matters because
	// status=open filters are the common fast-path.
	ClosedRatio float64
	// LabelDensity is the number of labels assigned per bead. Defaults to 2.
	LabelDensity int
	// AgentSessionsPerProject is the number of agent-session rows seeded into
	// each project's sessions.jsonl file. 0 means "do not seed sessions" —
	// the sessions harness target will still run but report against the
	// naturally-empty feed.
	AgentSessionsPerProject int
	// DocGraphFilesPerProject is the number of stub markdown files seeded
	// into each project so the DocGraph target exercises real IO. 0 means
	// the harness uses only whatever files already exist under the server's
	// working directory.
	DocGraphFilesPerProject int
}

// DefaultBeadFixtureSpec is the baseline fixture: 10 projects × 500 beads
// (5,000 total) with a modest amount of docgraph + sessions content. This is
// what `make bench-graphql` runs and what baseline reports compare against.
func DefaultBeadFixtureSpec() BeadFixtureSpec {
	return BeadFixtureSpec{
		Projects:                10,
		BeadsPerProject:         500,
		ClosedRatio:             0.3,
		LabelDensity:            2,
		AgentSessionsPerProject: 100, // 10 × 100 = 1,000 session rows
		DocGraphFilesPerProject: 4,
	}
}

// BeadFixture is a materialised on-disk workspace plus a live server.Server
// bound to it. Callers drive queries through Handler / State.
type BeadFixture struct {
	Spec          BeadFixtureSpec
	Server        *server.Server
	Handler       http.Handler
	Projects      []server.ProjectEntry
	TargetProject server.ProjectEntry
	TargetBeadID  string
	BeadIDsByProj map[string][]string
}

// TotalBeads returns the aggregate bead count across all seeded projects.
func (f *BeadFixture) TotalBeads() int {
	return f.Spec.Projects * f.Spec.BeadsPerProject
}

// BuildBeadFixture seeds the described workspace and returns a live fixture.
// It registers every project with the server's state so cross-project queries
// see all of them. The fixture is torn down automatically via tb.Cleanup.
func BuildBeadFixture(tb testing.TB, spec BeadFixtureSpec) *BeadFixture {
	tb.Helper()
	if spec.Projects < 1 {
		tb.Fatalf("perf: fixture needs at least 1 project, got %d", spec.Projects)
	}
	if spec.BeadsPerProject < 1 {
		tb.Fatalf("perf: fixture needs at least 1 bead per project, got %d", spec.BeadsPerProject)
	}
	if spec.LabelDensity <= 0 {
		spec.LabelDensity = 1
	}
	if spec.ClosedRatio < 0 {
		spec.ClosedRatio = 0
	}
	if spec.ClosedRatio > 1 {
		spec.ClosedRatio = 1
	}

	// Keep state out of the real user XDG dir so tests are hermetic.
	tb.Setenv("XDG_DATA_HOME", tb.TempDir())
	tb.Setenv("DDX_NODE_NAME", "ddx-perf-harness")

	root := tb.TempDir()
	projectPaths := make([]string, 0, spec.Projects)
	beadIDsByProj := make(map[string][]string, spec.Projects)
	var targetBeadID string

	for pi := 0; pi < spec.Projects; pi++ {
		projectPath := filepath.Join(root, fmt.Sprintf("project-%02d", pi))
		beads := seedProjectBeads(tb, projectPath, pi, spec)
		ids := make([]string, len(beads))
		for i, b := range beads {
			ids[i] = b.ID
		}
		beadIDsByProj[projectPath] = ids
		if spec.DocGraphFilesPerProject > 0 {
			seedProjectDocGraph(tb, projectPath, pi, spec.DocGraphFilesPerProject)
		}
		if spec.AgentSessionsPerProject > 0 {
			seedProjectSessions(tb, projectPath, pi, spec.AgentSessionsPerProject)
		}
		projectPaths = append(projectPaths, projectPath)
		if pi == spec.Projects-1 && len(beads) > 0 {
			// Target the final project's final bead so GetBeadSnapshot must
			// walk past the other (spec.Projects - 1) projects on the slow
			// path — this is what ddx-ad0db8fd cared about.
			targetBeadID = beads[len(beads)-1].ID
		}
	}

	srv := server.New(":0", projectPaths[0])
	tb.Cleanup(func() { _ = srv.Shutdown() })
	for _, p := range projectPaths[1:] {
		srv.RegisterProject(p)
	}

	projects := srv.State().GetProjects()
	if len(projects) != spec.Projects {
		tb.Fatalf("perf: registered %d projects, expected %d", len(projects), spec.Projects)
	}
	var targetProject server.ProjectEntry
	for _, proj := range projects {
		if proj.Path == projectPaths[len(projectPaths)-1] {
			targetProject = proj
			break
		}
	}
	if targetProject.ID == "" {
		tb.Fatalf("perf: target project was not registered")
	}

	return &BeadFixture{
		Spec:          spec,
		Server:        srv,
		Handler:       srv.Handler(),
		Projects:      projects,
		TargetProject: targetProject,
		TargetBeadID:  targetBeadID,
		BeadIDsByProj: beadIDsByProj,
	}
}

func seedProjectBeads(tb testing.TB, projectPath string, projectIdx int, spec BeadFixtureSpec) []bead.Bead {
	tb.Helper()
	store := bead.NewStore(filepath.Join(projectPath, ".ddx"))
	if err := store.Init(); err != nil {
		tb.Fatalf("perf: init bead store: %v", err)
	}
	baseTime := time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC)
	beads := make([]bead.Bead, 0, spec.BeadsPerProject)
	closedCutoff := int(float64(spec.BeadsPerProject) * spec.ClosedRatio)
	for bi := 0; bi < spec.BeadsPerProject; bi++ {
		id := fmt.Sprintf("ddx-perf-%02d-%04d", projectIdx, bi)
		now := baseTime.Add(time.Duration(projectIdx*spec.BeadsPerProject+bi) * time.Second)
		status := bead.StatusOpen
		if bi < closedCutoff {
			status = bead.StatusClosed
		}
		labels := make([]string, 0, spec.LabelDensity)
		for li := 0; li < spec.LabelDensity; li++ {
			labels = append(labels, fmt.Sprintf("label-%d", (bi+li)%7))
		}
		labels = append(labels, fmt.Sprintf("project-%02d", projectIdx))
		beads = append(beads, bead.Bead{
			ID:          id,
			Title:       fmt.Sprintf("Perf fixture bead %02d/%04d", projectIdx, bi),
			Status:      status,
			Priority:    bead.DefaultPriority,
			IssueType:   bead.DefaultType,
			CreatedAt:   now,
			UpdatedAt:   now,
			Labels:      labels,
			Description: "GraphQL perf fixture — realistic-shape bead with a multi-line description so parsing costs reflect typical payloads rather than artificially small bodies.",
		})
	}
	if err := store.WriteAll(beads); err != nil {
		tb.Fatalf("perf: seed bead store: %v", err)
	}
	return beads
}

func seedProjectDocGraph(tb testing.TB, projectPath string, projectIdx, count int) {
	tb.Helper()
	docsDir := filepath.Join(projectPath, "docs", "helix", "01-frame", "features")
	if err := os.MkdirAll(docsDir, 0o755); err != nil {
		tb.Fatalf("perf: mkdir docgraph: %v", err)
	}
	for di := 0; di < count; di++ {
		name := fmt.Sprintf("FEAT-%02d-%03d.md", projectIdx, di)
		path := filepath.Join(docsDir, name)
		body := fmt.Sprintf("---\nid: FEAT-%02d-%03d\ntitle: Perf fixture feature\n---\n\n# FEAT-%02d-%03d\n\nFixture body line 1\nFixture body line 2\n", projectIdx, di, projectIdx, di)
		if err := os.WriteFile(path, []byte(body), 0o644); err != nil {
			tb.Fatalf("perf: write docgraph file: %v", err)
		}
	}
}

func seedProjectSessions(tb testing.TB, projectPath string, projectIdx, count int) {
	tb.Helper()
	logDir := agent.SessionLogDirForWorkDir(projectPath)
	base := time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC)
	for si := 0; si < count; si++ {
		started := base.Add(time.Duration(projectIdx*count+si) * time.Minute)
		entry := agent.SessionIndexEntry{
			ID:         fmt.Sprintf("sess-%02d-%05d", projectIdx, si),
			ProjectID:  agent.ProjectIDForPath(projectPath),
			BeadID:     fmt.Sprintf("ddx-perf-%02d-%04d", projectIdx, si%10),
			Harness:    "claude",
			Surface:    "execute-bead",
			Model:      "claude-sonnet-4-6",
			StartedAt:  started,
			EndedAt:    started.Add(time.Duration(1000+si*10) * time.Millisecond),
			DurationMS: 1000 + si*10,
			Tokens:     1000 + si,
			Outcome:    "success",
			Effort:     "medium",
		}
		if err := agent.AppendSessionIndex(logDir, entry, started); err != nil {
			tb.Fatalf("perf: write session index row: %v", err)
		}
	}
}

// Environment returns a short footer describing the machine the benchmark ran
// on. Included verbatim in the baseline report (ddx-9ce6842a AC §2).
func Environment() string {
	return fmt.Sprintf("go=%s goos=%s goarch=%s cpu-cores=%d", runtime.Version(), runtime.GOOS, runtime.GOARCH, runtime.NumCPU())
}

---HARNESS---
package perf

import (
	"bytes"
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
	"sort"
	"testing"
	"time"
)

// Target is one entry in the benchmark matrix. Adding a new GraphQL query
// shape is a single-entry change: append a Target to Targets() with an
// in-process call and a GraphQL query string. Both are exercised on every
// harness run (ddx-9ce6842a AC §1).
type Target struct {
	Name       string
	Query      string
	InProcess  func(f *BeadFixture) error
	SkipInHTTP bool
}

// Result holds timings and metadata for one Target over one fixture.
type Result struct {
	Name       string       `json:"name"`
	Iterations int          `json:"iterations"`
	InProcess  Percentiles  `json:"in_process_ms"`
	HTTP       *Percentiles `json:"http_ms,omitempty"`
}

// Percentiles holds p50/p95/p99 in floating-point milliseconds.
type Percentiles struct {
	P50 float64 `json:"p50"`
	P95 float64 `json:"p95"`
	P99 float64 `json:"p99"`
}

// MatrixReport is the full output of one RunMatrix call — a list of per-target
// results plus fixture/environment metadata. It is what baseline reports
// compare against and what CI will diff in a follow-up bead.
type MatrixReport struct {
	GeneratedAt string    `json:"generated_at"`
	Environment string    `json:"environment"`
	Fixture     FixtureID `json:"fixture"`
	Targets     []Result  `json:"targets"`
}

// FixtureID is the fixture-shape metadata stamped into every report so a
// regression check can sanity-check that it's comparing apples to apples.
type FixtureID struct {
	Projects                int `json:"projects"`
	BeadsPerProject         int `json:"beads_per_project"`
	TotalBeads              int `json:"total_beads"`
	AgentSessionsPerProject int `json:"agent_sessions_per_project"`
}

// DefaultIterations is the sample size used when a run request does not
// override it. Chosen so p95/p99 are defensible on a 5,000-bead fixture
// without extending benchmark wall time past a few seconds.
const DefaultIterations = 40

// Targets returns the harness matrix covering the five query shapes named in
// ddx-9ce6842a AC §1: bead(id:), beadsByProject, beads (cross-project),
// docGraph, agentSessions. Adding a new target is a single append here.
func Targets() []Target {
	return []Target{
		{
			Name:  "bead",
			Query: `query Q($id: ID!) { bead(id: $id) { id title status updatedAt } }`,
			InProcess: func(f *BeadFixture) error {
				snap, ok := f.Server.State().GetBeadSnapshot(f.TargetBeadID)
				if !ok {
					return fmt.Errorf("bead not found: %s", f.TargetBeadID)
				}
				if snap.ID != f.TargetBeadID {
					return fmt.Errorf("unexpected bead id: %s", snap.ID)
				}
				return nil
			},
		},
		{
			Name:  "beadsByProject",
			Query: `query Q($project: String!, $first: Int!) { beadsByProject(projectID: $project, first: $first) { totalCount edges { node { id title status } } } }`,
			InProcess: func(f *BeadFixture) error {
				snaps := f.Server.State().GetBeadSnapshotsForProject(f.TargetProject.ID, "", "", "")
				if len(snaps) == 0 {
					return fmt.Errorf("no snapshots for project %s", f.TargetProject.ID)
				}
				return nil
			},
		},
		{
			Name:  "beadsByProject_statusOpen",
			Query: `query Q($project: String!, $first: Int!) { beadsByProject(projectID: $project, first: $first, status: "open") { totalCount edges { node { id } } } }`,
			InProcess: func(f *BeadFixture) error {
				snaps := f.Server.State().GetBeadSnapshotsForProject(f.TargetProject.ID, "open", "", "")
				if len(snaps) == 0 {
					return fmt.Errorf("no open snapshots for project %s", f.TargetProject.ID)
				}
				return nil
			},
		},
		{
			Name:  "beads_crossProject",
			Query: `query Q($first: Int!) { beads(first: $first) { totalCount edges { node { id title status } } } }`,
			InProcess: func(f *BeadFixture) error {
				snaps := f.Server.State().GetBeadSnapshots("", "", "", "")
				if len(snaps) != f.TotalBeads() {
					return fmt.Errorf("cross-project snapshots: want %d, got %d", f.TotalBeads(), len(snaps))
				}
				return nil
			},
		},
		{
			Name:  "docGraph",
			Query: `{ docGraph { rootDir documents { id path title } } }`,
			InProcess: func(f *BeadFixture) error {
				// The docGraph resolver is the in-process call — there is no
				// cheaper "direct state" equivalent for it, so we exercise
				// the HTTP path twice (once here via the handler, once in
				// the HTTP measurement below). The second invocation still
				// reports the distribution we care about.
				resp, err := postGraphQL(f.Handler, `{ docGraph { rootDir documents { id path title } } }`, nil)
				if err != nil {
					return err
				}
				if len(resp.Errors) > 0 {
					return fmt.Errorf("docGraph errors: %+v", resp.Errors)
				}
				return nil
			},
		},
		{
			Name:  "agentSessions",
			Query: `{ agentSessions(first: 50) { totalCount edges { node { id harness model } } } }`,
			InProcess: func(f *BeadFixture) error {
				sessions := f.Server.State().GetAgentSessionsGraphQL(nil, nil)
				_ = sessions // may be empty when fixture seeds 0 sessions; still exercised
				return nil
			},
		},
	}
}

// RunMatrix executes every Target `iterations` times, once via the in-process
// call and once via the HTTP handler, and returns the combined report. If
// iterations ≤ 0 the harness uses DefaultIterations.
func RunMatrix(tb testing.TB, f *BeadFixture, iterations int) MatrixReport {
	tb.Helper()
	if iterations <= 0 {
		iterations = DefaultIterations
	}
	targets := Targets()

	// Warm once per target so the first sample doesn't carry cold-cache cost
	// (bead-location index, os page cache). The p50/p95/p99 we report reflect
	// steady-state behaviour, which is what users feel on repeat navigations.
	for _, t := range targets {
		if t.InProcess != nil {
			_ = t.InProcess(f)
		}
		if !t.SkipInHTTP && t.Query != "" {
			_, _ = postGraphQL(f.Handler, t.Query, variablesFor(t, f))
		}
	}

	results := make([]Result, 0, len(targets))
	for _, t := range targets {
		r := Result{Name: t.Name, Iterations: iterations}
		if t.InProcess != nil {
			samples := make([]time.Duration, 0, iterations)
			for i := 0; i < iterations; i++ {
				start := time.Now()
				if err := t.InProcess(f); err != nil {
					tb.Fatalf("perf: target %s in-process failed: %v", t.Name, err)
				}
				samples = append(samples, time.Since(start))
			}
			r.InProcess = percentileMillis(samples)
		}
		if !t.SkipInHTTP && t.Query != "" {
			samples := make([]time.Duration, 0, iterations)
			vars := variablesFor(t, f)
			for i := 0; i < iterations; i++ {
				start := time.Now()
				resp, err := postGraphQL(f.Handler, t.Query, vars)
				elapsed := time.Since(start)
				if err != nil {
					tb.Fatalf("perf: target %s HTTP failed: %v", t.Name, err)
				}
				if len(resp.Errors) > 0 {
					tb.Fatalf("perf: target %s graphql errors: %+v", t.Name, resp.Errors)
				}
				samples = append(samples, elapsed)
			}
			p := percentileMillis(samples)
			r.HTTP = &p
		}
		results = append(results, r)
	}

	return MatrixReport{
		GeneratedAt: time.Now().UTC().Format(time.RFC3339),
		Environment: Environment(),
		Fixture: FixtureID{
			Projects:                f.Spec.Projects,
			BeadsPerProject:         f.Spec.BeadsPerProject,
			TotalBeads:              f.TotalBeads(),
			AgentSessionsPerProject: f.Spec.AgentSessionsPerProject,
		},
		Targets: results,
	}
}

func variablesFor(t Target, f *BeadFixture) map[string]any {
	switch t.Name {
	case "bead":
		return map[string]any{"id": f.TargetBeadID}
	case "beadsByProject", "beadsByProject_statusOpen":
		return map[string]any{"project": f.TargetProject.ID, "first": 50}
	case "beads_crossProject":
		return map[string]any{"first": 50}
	default:
		return nil
	}
}

type graphQLResponse struct {
	Data   json.RawMessage  `json:"data"`
	Errors []map[string]any `json:"errors,omitempty"`
}

// postGraphQL submits one GraphQL query through the HTTP handler and returns
// the decoded response. It is the single HTTP entry point used by both the
// harness and the smoke tests so they share transport timings.
func postGraphQL(h http.Handler, query string, variables map[string]any) (graphQLResponse, error) {
	payload := map[string]any{"query": query}
	if variables != nil {
		payload["variables"] = variables
	}
	raw, err := json.Marshal(payload)
	if err != nil {
		return graphQLResponse{}, fmt.Errorf("marshal: %w", err)
	}
	req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewReader(raw))
	req.Header.Set("Content-Type", "application/json")
	req.RemoteAddr = "127.0.0.1:12345"
	w := httptest.NewRecorder()
	h.ServeHTTP(w, req)
	if w.Code != http.StatusOK {
		return graphQLResponse{}, fmt.Errorf("status %d: %s", w.Code, w.Body.String())
	}
	var resp graphQLResponse
	if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
		return graphQLResponse{}, fmt.Errorf("decode: %w body=%s", err, w.Body.String())
	}
	return resp, nil
}

// PostGraphQL is the exported counterpart used by smoke tests in other
// packages that want to reuse the harness's HTTP entry point.
func PostGraphQL(h http.Handler, query string, variables map[string]any) error {
	resp, err := postGraphQL(h, query, variables)
	if err != nil {
		return err
	}
	if len(resp.Errors) > 0 {
		return fmt.Errorf("graphql errors: %+v", resp.Errors)
	}
	return nil
}

func percentileMillis(samples []time.Duration) Percentiles {
	if len(samples) == 0 {
		return Percentiles{}
	}
	sort.Slice(samples, func(i, j int) bool { return samples[i] < samples[j] })
	return Percentiles{
		P50: toMillis(percentile(samples, 50)),
		P95: toMillis(percentile(samples, 95)),
		P99: toMillis(percentile(samples, 99)),
	}
}

func percentile(sorted []time.Duration, pct int) time.Duration {
	if len(sorted) == 0 {
		return 0
	}
	idx := (len(sorted)*pct + 99) / 100
	if idx < 1 {
		idx = 1
	}
	if idx > len(sorted) {
		idx = len(sorted)
	}
	return sorted[idx-1]
}

func toMillis(d time.Duration) float64 {
	return float64(d.Microseconds()) / 1000.0
}

